<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<title>Falling Sand Sandbox</title>
<style>
  body{margin:0;background:#222;color:#eee;font-family:sans-serif;display:flex;flex-direction:column;align-items:center;}
  #controls{margin-top:10px;}
  button{background:#444;border:none;padding:6px 12px;margin:2px;color:#eee;border-radius:4px;cursor:pointer;}
  button.active{background:#888;}
  canvas{border:1px solid #555;background:#111;}
</style>
</head>
<body>
<canvas id="sand" width="400" height="400"></canvas>
<div id="controls">
  <button id="mat-sand">Sand</button>
  <button id="mat-water">Water</button>
  <button id="mat-wall">Wall</button>
  <button id="mat-acid">Acid</button>
  <button id="mat-empty">Eraser</button>
  <button id="clear">Clear</button>
</div>

<script>
(() => {
  const canvas = document.getElementById('sand');
  const ctx = canvas.getContext('2d');
  const w = 80, h = 80; // grid size
  const cellSize = canvas.width / w;
  const materials = ['empty','sand','water','wall','acid'];
  let grid = new Uint8Array(w*h); // store indices of materials

  function idx(x,y){return y*w+x;}
  function get(x,y){if(x<0||x>=w||y<0||y>=h)return 4; return materials[grid[idx(x,y)]];}
  function set(x,y,m){if(x<0||x>=w||y<0||y>=h)return; grid[idx(x,y)] = materials.indexOf(m);}

  // API
  window.sim = {
    w, h,
    tick(n=1){
      for(let step=0;step<n;step++){
        for(let y=h-1;y>=0;y--){
          for(let x=0;x<w;x++){
            const i=idx(x,y);
            const matIdx=grid[i];
            if(matIdx===0)continue; // empty
            const mat = materials[matIdx];
            let nx=x, ny=y;
            if(mat==='sand'){
              if(get(x,y+1)==='empty'){ny=y+1;}
              else{
                const dirs=[-1,1]; if(Math.random()<0.5)[dirs[0],dirs[1]]=[dirs[1],dirs[0]];
                for(const d of dirs){
                  if(get(x+d,y+1)==='empty'){nx=x+d;ny=y+1;break;}
                }
              }
            }else if(mat==='water'){
              if(get(x,y+1)==='empty'){ny=y+1;}
              else{
                const dirs=[-1,1]; if(Math.random()<0.5)[dirs[0],dirs[1]]=[dirs[1],dirs[0]];
                for(const d of dirs){
                  if(get(x+d,y)==='empty'){nx=x+d;break;}
                }
              }
            }else if(mat==='acid'){
              if(get(x,y+1)==='empty'){ny=y+1;}
              else{
                const dirs=[-1,1]; if(Math.random()<0.5)[dirs[0],dirs[1]]=[dirs[1],dirs[0]];
                for(const d of dirs){
                  if(get(x+d,y)==='empty'){nx=x+d;break;}
                }
              }
              // dissolve
              const targets=[[x-1,y],[x+1,y],[x,y-1],[x,y+1]];
              for(const [tx,ty] of targets){
                const t=get(tx,ty);
                if(t==='sand'||t==='wall'){
                  set(tx,ty,'empty');
                }
              }
            }else if(mat==='wall'){continue;}
            if(nx!==x||ny!==y){
              grid[idx(x,y)]=0;
              grid[idx(nx,ny)]=matIdx;
            }
          }
        }
      }
    },
    get(x,y){return get(x,y);},
    set(x,y,m){set(x,y,m);},
    clear(){grid.fill(0);}
  };

  // Rendering
  function render(){
    ctx.clearRect(0,0,canvas.width,canvas.height);
    for(let y=0;y<h;y++){
      for(let x=0;x<w;x++){
        const matIdx=grid[idx(x,y)];
        if(matIdx===0)continue;
        switch(materials[matIdx]){
          case 'sand': ctx.fillStyle='#D2B48C';break;
          case 'water':ctx.fillStyle='#4A90E2';break;
          case 'wall': ctx.fillStyle='#555';break;
          case 'acid': ctx.fillStyle='#FF0000';break;
        }
        ctx.fillRect(x*cellSize,y*cellSize,cellSize,cellSize);
      }
    }
  }

  // Animation loop
  function loop(){render();requestAnimationFrame(loop);}
  requestAnimationFrame(loop);

  // Controls
  let currentMat='sand';
  const matButtons=document.querySelectorAll('#mat-sand,#mat-water,#mat-wall,#mat-acid,#mat-empty');
  matButtons.forEach(btn=>{
    btn.addEventListener('click',()=>{
      matButtons.forEach(b=>b.classList.remove('active'));
      btn.classList.add('active');
      currentMat=btn.id.split('-')[1];
    });
  });
  document.getElementById('clear').addEventListener('click',()=>{window.sim.clear();});

  // Painting
  let painting=false;
  canvas.addEventListener('mousedown',(e)=>{painting=true;paint(e);});
  canvas.addEventListener('mousemove',(e)=>{if(painting)paint(e);});
  window.addEventListener('mouseup',()=>{painting=false;});
  function paint(e){
    const rect=canvas.getBoundingClientRect();
    const x=Math.floor((e.clientX-rect.left)/cellSize);
    const y=Math.floor((e.clientY-rect.top)/cellSize);
    if(x<0||x>=w||y<0||y>=h)return;
    window.sim.set(x,y,currentMat==='empty'?'empty':currentMat);
  }
})();
</script>
</body>
</html>
